module.render:
const color = args.color || 'var(--accent-color)';
const vals = sections.join(' ').split(/[\s,]+/).map(parseFloat).filter(Number.isFinite);
if (!vals.length) return `<div>(histogram: put numbers in the body)</div>`;
let lo = args.min !== '' && args.min != null ? parseFloat(args.min) : Math.min(...vals);
let hi = args.max !== '' && args.max != null ? parseFloat(args.max) : Math.max(...vals);
if (!Number.isFinite(lo)) lo = 0; if (!Number.isFinite(hi)) hi = 1;
if (hi === lo) hi = lo + 1;
let bins = parseInt(args.bins, 10);
if (!Number.isFinite(bins) || bins < 1) bins = Math.max(3, Math.min(12, Math.round(Math.sqrt(vals.length))));
const w = (hi - lo) / bins;
const counts = new Array(bins).fill(0);
vals.forEach((v) => {
  if (v < lo || v > hi) return;
  counts[Math.min(bins - 1, Math.floor((v - lo) / w))]++;
});
const peak = Math.max(...counts) || 1;
const fmt = (v) => { const r = +v.toFixed(2); return String(r); };
let bars = '';
counts.forEach((c, i) => {
  bars += `<div class="mdp-hg-col"><div class="mdp-hg-count">${c || ''}</div>` +
    `<div class="mdp-hg-bar" style="height:${((c / peak) * 100).toFixed(1)}%;"></div>` +
    `<div class="mdp-hg-edge">${fmt(lo + i * w)}</div></div>`;
});
return `\n\n<div class="mdp-mod-histogram" style="--hg-c:${color};"><div class="mdp-hg-plot">${bars}` +
  `<div class="mdp-hg-col mdp-hg-last"><div class="mdp-hg-edge">${fmt(hi)}</div></div></div></div>\n\n`;
